class Solution:
    def maxActiveSectionsAfterTrade(self, s):
        t = '1' + s + '1'
        n = len(t)
        runs = []
        i = 0
        while i < n:
            j = i
            while j < n and t[j] == t[i]:
                j += 1
            runs.append((i, j, t[i]))
            i = j
        base = s.count('1')
        best = base
        for idx in range(1, len(runs) - 1):
            start, end, ch = runs[idx]
            if ch != '1':
                continue
            grid = list(t)
            for p in range(start, end):
                grid[p] = '0'
            left = start
            while left > 0 and grid[left - 1] == '0':
                left -= 1
            right = end
            while right < n and grid[right] == '0':
                right += 1
            for p in range(left, right):
                grid[p] = '1'
            count = ''.join(grid[1:-1]).count('1')
            if count > best:
                best = count
        return best

