var maxActiveSectionsAfterTrade = function(s) {
    const t = '1' + s + '1';
    const n = t.length;
    const runs = [];
    let i = 0;
    while (i < n) {
        let j = i;
        while (j < n && t[j] === t[i]) j++;
        runs.push([t[i], j - i]);
        i = j;
    }
    let best = 0;
    for (let idx = 1; idx < runs.length - 1; idx++) {
        if (runs[idx][0] === '1') {
            const gain = runs[idx - 1][1] + runs[idx + 1][1];
            if (gain > best) best = gain;
        }
    }
    let ones = 0;
    for (let i2 = 0; i2 < s.length; i2++) if (s[i2] === '1') ones++;
    return ones + best;
};
